function getHostname(url: string) {
  try {
    return new URL(url).hostname.replace(/^www\./, "");
  } catch {
    return url;
  }
}

function getSourceInitial(source: string, url: string) {
  const label = source?.trim() || getHostname(url);
  return label.charAt(0).toUpperCase();
}

function EmptyState({ onAsk }: { onAsk: (q: string) => void }) {
  const examples = [
    "What would happen if Earth stopped spinning?",
    "Why can’t we travel faster than light?",
    "How does the brain store memories?",
    "What is the Fermi Paradox?",
  ];

  return (
    <div className="mx-auto mt-16 max-w-2xl text-center">
      <h1 className="text-3xl font-semibold tracking-tight text-white">
        Ask better science questions.
      </h1>

      <p className="mt-4 text-[var(--muted)]">
        SciSeek gives structured, evidence-based answers — not just opinions.
      </p>

      <div className="mt-8 grid gap-3">
        {examples.map((q) => (
          <button
            key={q}
            onClick={() => onAsk(q)}
            className="rounded-xl border border-[var(--border)] bg-[var(--panel)] px-4 py-3 text-left text-sm text-[var(--foreground)] transition hover:border-[var(--primary)] hover:text-white hover:shadow-[0_0_12px_rgba(96,165,250,0.15)]"
          >
            {q}
          </button>
        ))}
      </div>
    </div>
  );
}

export default function HomePage() {
  const [question, setQuestion] = useState("");
  const [answer, setAnswer] = useState<string | null>(null);
  const [answerData, setAnswerData] = useState<AskResponse | null>(null);
  const [activeQuestion, setActiveQuestion] = useState<string | null>(null);
  const [historyItems, setHistoryItems] = useState<HistoryItem[]>([]);
  const [isLoading, setIsLoading] = useState(false);

  const textareaRef = useRef<HTMLTextAreaElement>(null);
  const topRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const savedHistory = localStorage.getItem("sciseek-history");

    if (savedHistory) {
      try {
        setHistoryItems(JSON.parse(savedHistory));
      } catch {
        setHistoryItems(starterHistory);
      }
    } else {
      setHistoryItems(starterHistory);
    }
  }, []);

  useEffect(() => {
    localStorage.setItem("sciseek-history", JSON.stringify(historyItems));
  }, [historyItems]);

  function resizeTextarea() {
    if (textareaRef.current) {
      textareaRef.current.style.height = "auto";
      textareaRef.current.style.height = `${textareaRef.current.scrollHeight}px`;
    }
  }

  function handleNewQuestion() {
    setQuestion("");
    setAnswer(null);
    setAnswerData(null);
    setActiveQuestion(null);

    if (topRef.current) {
      topRef.current.scrollIntoView({ behavior: "smooth", block: "start" });
    }

    requestAnimationFrame(() => {
      if (textareaRef.current) {
        textareaRef.current.style.height = "auto";
        textareaRef.current.focus();
      }
    });
  }

  function handleHistoryClick(item: HistoryItem) {
    setQuestion(item.question);
    setAnswer(item.answer);
    setAnswerData(item.answerData ?? null);
    setActiveQuestion(item.question);

    requestAnimationFrame(() => {
      resizeTextarea();
    });
  }

  async function handleAskWithQuestion(questionText?: string) {
    const trimmedQuestion = (questionText ?? question).trim();
    if (!trimmedQuestion || isLoading) return;

    setQuestion(trimmedQuestion);
    setAnswer(null);
    setAnswerData(null);
    setActiveQuestion(null);
    setIsLoading(true);

    if (topRef.current) {
      topRef.current.scrollIntoView({ behavior: "smooth", block: "start" });
    }

    requestAnimationFrame(() => {
      if (textareaRef.current) {
        resizeTextarea();
        textareaRef.current.focus();
      }
    });

    let newAnswer = "";
    let newAnswerData: AskResponse | null = null;

    try {
      const res = await fetch("http://127.0.0.1:8000/api/ask", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({
          question: trimmedQuestion,
          tier: "free",
          mode: "standard",
        }),
      });

      const data: AskResponse = await res.json();

      if (!res.ok) {
        throw new Error(`Request failed with status ${res.status}`);
      }

      newAnswerData = data;

      if (data.refusal_message) {
        newAnswer = data.refusal_message;
      } else {
        const parts: string[] = [];

        if (data.hook) parts.push(data.hook);
        if (data.short_summary) parts.push(data.short_summary);

        if (data.sections?.length) {
          data.sections.forEach((section) => {
            parts.push(`${section.title}\n${section.body}`);
          });
        }

        if (data.key_points?.length) {
          parts.push(`Key points:\n- ${data.key_points.join("\n- ")}`);
        }

        newAnswer = parts.join("\n\n").trim();
      }

      if (!newAnswer) {
        newAnswer = "No answer was returned.";
      }
    } catch (error) {
      console.error("Ask request failed:", error);
      newAnswer = "Something went wrong. Please try again.";
      newAnswerData = null;
    } finally {
      setIsLoading(false);
    }

    setAnswer(newAnswer);
    setAnswerData(newAnswerData);
    setActiveQuestion(trimmedQuestion);

    const newItem: HistoryItem = {
      id: crypto.randomUUID(),
      question: trimmedQuestion,
      answer: newAnswer,
      answerData: newAnswerData,
    };

    setHistoryItems((prev) => {
      const withoutDuplicate = prev.filter(
        (item) => item.question.toLowerCase() !== trimmedQuestion.toLowerCase()
      );

      return [newItem, ...withoutDuplicate];
    });
  }

  async function handleAsk() {
    await handleAskWithQuestion();
  }

  function askRelatedQuestion(related: string) {
    setQuestion(related);
    setAnswer(null);
    setAnswerData(null);
    setActiveQuestion(null);

    if (topRef.current) {
      topRef.current.scrollIntoView({ behavior: "smooth", block: "start" });
    }

    requestAnimationFrame(() => {
      if (textareaRef.current) {
        resizeTextarea();
        textareaRef.current.focus();
      }
    });

    setTimeout(() => {
      handleAskWithQuestion(related);
    }, 0);
  }

  return (
    <div
      ref={topRef}
      className="min-h-screen bg-[var(--background)] text-[var(--foreground)]"
    >
      <div className="flex min-h-screen">
        <aside className="hidden w-80 shrink-0 border-r border-[var(--border)] bg-[var(--sidebar)] lg:flex lg:flex-col">
          <div className="border-b border-[var(--border)] p-4">
            <button
              onClick={handleNewQuestion}
              className="w-full rounded-xl bg-[var(--primary)] px-4 py-3 text-left text-sm font-medium text-black transition hover:opacity-90"
            >
              + New Question
            </button>
          </div>

          <div className="flex-1 overflow-y-auto p-3">
            <div className="mb-3 px-2 text-xs font-semibold uppercase tracking-wide text-[var(--muted)]">
              Recent Questions
            </div>

            <div className="space-y-1">
              {historyItems.map((item) => (
                <button
                  key={item.id}
                  onClick={() => handleHistoryClick(item)}
                  className={`w-full rounded-lg px-3 py-2 text-left text-sm transition ${
                    activeQuestion === item.question
                      ? "bg-[var(--sidebar-active)] text-white"
                      : "text-[var(--muted)] hover:bg-[var(--sidebar-hover)] hover:text-white"
                  }`}
                >
                  {item.question}
                </button>
              ))}
            </div>
          </div>
        </aside>

        <div className="flex min-w-0 flex-1 flex-col">
          <header className="border-b border-[var(--border)] p-4">
            <div className="text-lg font-semibold">SciSeek</div>
          </header>

          <main className="mx-auto w-full max-w-5xl flex-1 p-6 space-y-6">
            <div className="rounded-2xl border border-[var(--border)] bg-[var(--card)] p-4">
              <textarea
                ref={textareaRef}
                value={question}
                onChange={(e) => setQuestion(e.target.value)}
                onInput={(e) => {
                  const el = e.currentTarget;
                  el.style.height = "auto";
                  el.style.height = `${el.scrollHeight}px`;
                }}
                onKeyDown={(e) => {
                  if (e.key === "Enter" && !e.shiftKey) {
                    e.preventDefault();
                    handleAsk();
                  }
                }}
                placeholder="Ask anything scientific..."
                rows={1}
                className="w-full resize-none bg-transparent text-white outline-none placeholder:text-[var(--muted)]"
              />

              <div className="mt-4 flex justify-end">
                <button
                  onClick={handleAsk}
                  disabled={isLoading}
                  className="flex items-center gap-2 rounded-xl bg-[var(--primary)] px-4 py-2 text-black transition hover:opacity-90 disabled:cursor-not-allowed disabled:opacity-60"
                >
                  {isLoading && (
                    <div className="h-3 w-3 animate-spin rounded-full border-2 border-black border-t-transparent" />
                  )}
                  {isLoading ? "Thinking..." : "Ask"}
                </button>
              </div>

              {isLoading && (
                <div className="mt-3 text-sm text-[var(--muted)]">
                  Searching...
                </div>
              )}
            </div>

            {isLoading ? (
              <LoadingSkeleton />
            ) : answerData ? (
              <div className="space-y-6">
                {answerData.refusal_message ? (
                  <section className="rounded-2xl border border-[var(--border)] bg-[var(--card)] p-6">
                    <div className="mb-2 text-sm text-[var(--muted)]">Answer</div>
                    <p className="leading-7">{answerData.refusal_message}</p>
                  </section>
                ) : (
                  <>
                    {(answerData.hook || answerData.short_summary) && (
                      <section className="rounded-2xl border border-[var(--border)] bg-[var(--card)] p-6 shadow-[0_0_0_1px_rgba(96,165,250,0.05),0_8px_30px_rgba(0,0,0,0.25)]">
                        {answerData.hook && (
                          <h2 className="text-3xl font-semibold leading-tight tracking-tight text-white">
                            {answerData.hook}
                          </h2>
                        )}

                        {answerData.short_summary && (
                          <p className="mt-3 leading-7 text-[var(--foreground)]">
                            {answerData.short_summary}
                          </p>
                        )}
                      </section>
                    )}

                    {answerData.sections && answerData.sections.length > 0 && (
                      <section className="space-y-4">
                        {answerData.sections.map((section, index) => (
                          <div
                            key={`${section.title}-${index}`}
                            className="rounded-2xl border border-[var(--border)] bg-[var(--card)] p-6 transition hover:border-[var(--primary)]/40"
                          >
                            <h3 className="text-lg font-semibold text-white">
                              {section.title}
                            </h3>
                            <p className="mt-3 whitespace-pre-wrap leading-7 text-[var(--foreground)]">
                              {section.body}
                            </p>
                          </div>
                        ))}
                      </section>
                    )}

                    {answerData.key_points && answerData.key_points.length > 0 && (
                      <section className="rounded-2xl border border-[var(--border)] bg-[var(--card)] p-6">
                        <h3 className="text-lg font-semibold text-white">
                          Key Points
                        </h3>
                        <ul className="mt-5 space-y-4">
                          {answerData.key_points.map((point, index) => (
                            <li
                              key={`${point}-${index}`}
                              className="flex items-start gap-3"
                            >
                              <span className="mt-2 h-2 w-2 shrink-0 rounded-full bg-[var(--primary)] shadow-[0_0_6px_rgba(96,165,250,0.6)]" />
                              <span className="leading-7 text-[var(--foreground)]">
                                {point}
                              </span>
                            </li>
                          ))}
                        </ul>
                      </section>
                    )}

                    {answerData.related_questions &&
                      answerData.related_questions.length > 0 && (
                        <section className="rounded-2xl border border-[var(--border)] bg-[var(--card)] p-6">
                          <h3 className="text-lg font-semibold text-white">
                            Related Questions
                          </h3>
                          <div className="mt-4 flex flex-wrap gap-2">
                            {answerData.related_questions.map((related, index) => (
                              <button
                                key={`${related}-${index}`}
                                onClick={() => askRelatedQuestion(related)}
                                className="rounded-full border border-[var(--border)] bg-[var(--panel)] px-3 py-2 text-sm text-[var(--foreground)] transition hover:border-[var(--primary)] hover:text-white hover:shadow-[0_0_10px_rgba(96,165,250,0.2)]"
                              >
                                {related}
                              </button>
                            ))}
                          </div>
                        </section>
                      )}

                    {answerData.citations && answerData.citations.length > 0 && (
                      <section className="rounded-2xl border border-[var(--border)] bg-[var(--card)] p-6">
                        <div className="mb-4 flex items-center justify-between gap-4">
                          <h3 className="text-lg font-semibold text-white">
                            Sources
                          </h3>
                          <div className="text-xs uppercase tracking-wide text-[var(--muted)]">
                            {answerData.citations.length} source{answerData.citations.length === 1 ? "" : "s"}
                          </div>
                        </div>

                        <div className="space-y-3">
                          {answerData.citations.map((citation, index) => {
                            const hostname = getHostname(citation.url);
                            const sourceLabel = citation.source || hostname;
                            const initial = getSourceInitial(citation.source, citation.url);

                            return (
                              <a
                                key={`${citation.url}-${index}`}
                                href={citation.url}
                                target="_blank"
                                rel="noreferrer"
                                className="group block rounded-2xl border border-[var(--border)] bg-[var(--panel)] p-4 transition hover:border-[var(--primary)] hover:bg-white/[0.02] hover:shadow-[0_0_18px_rgba(96,165,250,0.12)]"
                              >
                                <div className="flex items-start gap-4">
                                  <div className="flex h-10 w-10 shrink-0 items-center justify-center rounded-xl border border-[var(--border)] bg-[var(--background)] text-sm font-semibold text-white">
                                    {initial}
                                  </div>

                                  <div className="min-w-0 flex-1">
                                    <div className="flex items-start justify-between gap-3">
                                      <div className="min-w-0">
                                        <div className="line-clamp-2 text-sm font-medium leading-6 text-white">
                                          {citation.title}
                                        </div>

                                        <div className="mt-2 flex flex-wrap items-center gap-x-2 gap-y-1 text-xs">
                                          <span className="rounded-full border border-[var(--border)] bg-white/[0.03] px-2 py-1 text-[var(--foreground)]">
                                            {sourceLabel}
                                          </span>
                                          <span className="text-[var(--muted)]">
                                            {hostname}
                                          </span>
                                        </div>
                                      </div>

                                      <div className="shrink-0 text-[var(--muted)] transition group-hover:text-[var(--primary)]">
                                        ↗
                                      </div>
                                    </div>
                                  </div>
                                </div>
                              </a>
                            );
                          })}
                        </div>
                      </section>
                    )}
                  </>
                )}
              </div>
              ) : answer ? (
                <div className="whitespace-pre-wrap rounded-2xl border border-[var(--border)] bg-[var(--card)] p-6">
                  <div className="mb-2 text-sm text-[var(--muted)]">Answer</div>
                  <p>{answer}</p>
                </div>
              ) : (
                <EmptyState onAsk={(q) => handleAskWithQuestion(q)} />
              )}
          </main>
        </div>
      </div>
    </div>
  );
}